// Extract WhatsApp message data from Meta Cloud API payload
const input = $input.first().json;

// Parse Meta webhook structure
const message = input.entry?.[0]?.changes?.[0]?.value?.messages?.[0];
const metadata = input.entry?.[0]?.changes?.[0]?.value?.metadata;

if (!message) {
  throw new Error('Invalid WhatsApp message structure');
}

// Normalize to Janam IngestEventRequest
const janamPayload = {
  channel: 'whatsapp',
  platform: 'meta-cloud-api',
  sender_id: message.from,
  message_text: message.text?.body || '',
  external_event_id: message.id,
  timestamp_iso: new Date(parseInt(message.timestamp) * 1000).toISOString(),
  media_type: 'text',
  anonymous_mode: true,  // WhatsApp reporters stay anonymous
  raw_payload: null      // Don't store raw Meta payload for privacy
};

return { janamPayload };

// Generate HMAC-SHA256 signature for Janam /ingest/n8n
const crypto = require('crypto');
const input = $input.first().json;
const janamPayload = input.janamPayload;

// Get webhook secret from n8n environment
const secret = $env.JANAM_N8N_WEBHOOK_SECRET;
if (!secret) {
  throw new Error('Missing JANAM_N8N_WEBHOOK_SECRET in n8n environment variables');
}

// Generate timestamp and signature
const timestamp = Math.floor(Date.now() / 1000).toString();
const payloadString = JSON.stringify(janamPayload);
const messageToSign = `${timestamp}.${payloadString}`;
const signature = crypto
  .createHmac('sha256', secret)
  .update(messageToSign)
  .digest('hex');

return {
  payload: janamPayload,
  headers: {
    'X-Janam-Webhook-Timestamp': timestamp,
    'X-Janam-Webhook-Signature': `sha256=${signature}`,
    'Content-Type': 'application/json',
    'X-API-Key': $env.JANAM_WRITE_API_KEY
  },
  url: $env.JANAM_INGEST_URL || 'http://localhost:8000/ingest/n8n'
};
